// src/App.js

import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import EventManage from './components/EventManage'; 
import EventDetail from './components/EventDetail'; 
import EventRegister from './components/EventRegister';
import VendorRegister from './components/VendorRegister'; // Import the component

function App() {
  return (
    <Router>
      <div className="App">
        <div>
          <Link to="/event/manage">Manage Events</Link>
          <Link to="/vendor/manage">Manage Vendors</Link>
        </div>
        <Routes>
          <Route path="/" element={<EventManage />} index />
          <Route path="/event/:id" element={<EventDetail />} />
          <Route path="/event/register" element={<EventRegister />} />
          <Route path="/vendor/register" element={<VendorRegister />} /> // Add this line
        </Routes>
      </div>
    </Router>
  );
}

export default App;
